#pragma OPENCL EXTENSION cl_khr_fp64 : enable

#define GAMMA 1.4f
#define NDIM 3
#define NNB 4
#define RK 3
#define VAR_DENSITY 0
#define VAR_MOMENTUM 1
#define VAR_DENSITY_ENERGY (VAR_MOMENTUM+NDIM)
#define NVAR (VAR_DENSITY_ENERGY+1)

typedef struct{
    float x;
    float y;
    float z;
} float3;

kernel void initialize_variables(int nelr, float* variables, const float* ff_variable) {
    int i = get_global_id(0);
    if (i < nelr) {
        for(int j = 0; j < NVAR; j++) {
            variables[i + j*nelr] = ff_variable[j];
        }
    }
}

kernel void compute_step_factor(int nelr, float* variables, float* areas, float* step_factors) {
    int i = get_global_id(0);
    if (i < nelr) {
        float density = variables[i + VAR_DENSITY*nelr];
        float momentum_x = variables[i + (VAR_MOMENTUM+0)*nelr];
        float momentum_y = variables[i + (VAR_MOMENTUM+1)*nelr];
        float momentum_z = variables[i + (VAR_MOMENTUM+2)*nelr];
        float density_energy = variables[i + VAR_DENSITY_ENERGY*nelr];

        float velocity_x = momentum_x / density;
        float velocity_y = momentum_y / density;
        float velocity_z = momentum_z / density;

        float speed_sqd = velocity_x*velocity_x + velocity_y*velocity_y + velocity_z*velocity_z;
        float pressure = (GAMMA-1.0f)*(density_energy - 0.5f*density*speed_sqd);
        float speed_of_sound = sqrtf(GAMMA*pressure/density);

        step_factors[i] = 0.5f / (sqrtf(areas[i]) * (sqrtf(speed_sqd) + speed_of_sound));
    }
}

kernel void compute_flux(int nelr, int* elements_surrounding_elements, float* normals, float* variables, float* fluxes, const float* ff_variable, const float3* ff_flux_contribution_density_energy, const float3* ff_flux_contribution_momentum_x, const float3* ff_flux_contribution_momentum_y, const float3* ff_flux_contribution_momentum_z) {
    float smoothing_coefficient = 0.2f;
    int i = get_global_id(0);

    if (i < nelr) {
        float density_i = variables[i + VAR_DENSITY*nelr];
        float momentum_i_x = variables[i + (VAR_MOMENTUM+0)*nelr];
        float momentum_i_y = variables[i + (VAR_MOMENTUM+1)*nelr];
        float momentum_i_z = variables[i + (VAR_MOMENTUM+2)*nelr];
        float density_energy_i = variables[i + VAR_DENSITY_ENERGY*nelr];

        float velocity_i_x = momentum_i_x / density_i;
        float velocity_i_y = momentum_i_y / density_i;
        float velocity_i_z = momentum_i_z / density_i;

        float speed_sqd_i = velocity_i_x*velocity_i_x + velocity_i_y*velocity_i_y + velocity_i_z*velocity_i_z;
        float speed_i = sqrtf(speed_sqd_i);
        float pressure_i = (GAMMA-1.0f)*(density_energy_i - 0.5f*density_i*speed_sqd_i);
        float speed_of_sound_i = sqrtf(GAMMA*pressure_i/density_i);

        float fc_momentum_i_x_x = velocity_i_x*momentum_i_x + pressure_i;
        float fc_momentum_i_x_y = velocity_i_x*momentum_i_y;
        float fc_momentum_i_x_z = velocity_i_x*momentum_i_z;

        float fc_momentum_i_y_x = fc_momentum_i_x_y;
        float fc_momentum_i_y_y = velocity_i_y*momentum_i_y + pressure_i;
        float fc_momentum_i_y_z = velocity_i_y*momentum_i_z;

        float fc_momentum_i_z_x = fc_momentum_i_x_z;
        float fc_momentum_i_z_y = fc_momentum_i_y_z;
        float fc_momentum_i_z_z = velocity_i_z*momentum_i_z + pressure_i;

        float de_p_i = density_energy_i + pressure_i;
        float fc_density_energy_i_x = velocity_i_x*de_p_i;
        float fc_density_energy_i_y = velocity_i_y*de_p_i;
        float fc_density_energy_i_z = velocity_i_z*de_p_i;

        float flux_i_density = 0.0f;
        float flux_i_momentum_x = 0.0f;
        float flux_i_momentum_y = 0.0f;
        float flux_i_momentum_z = 0.0f;
        float flux_i_density_energy = 0.0f;

        for(int j = 0; j < NNB; j++) {
            int nb = elements_surrounding_elements[i + j*nelr];
            float normal_x = normals[i + (j + 0*NNB)*nelr];
            float normal_y = normals[i + (j + 1*NNB)*nelr];
            float normal_z = normals[i + (j + 2*NNB)*nelr];
            float normal_len = sqrtf(normal_x*normal_x + normal_y*normal_y + normal_z*normal_z);

            if(nb >= 0) {
                float density_nb = variables[nb + VAR_DENSITY*nelr];
                float momentum_nb_x = variables[nb + (VAR_MOMENTUM+0)*nelr];
                float momentum_nb_y = variables[nb + (VAR_MOMENTUM+1)*nelr];
                float momentum_nb_z = variables[nb + (VAR_MOMENTUM+2)*nelr];
                float density_energy_nb = variables[nb + VAR_DENSITY_ENERGY*nelr];

                float velocity_nb_x = momentum_nb_x / density_nb;
                float velocity_nb_y = momentum_nb_y / density_nb;
                float velocity_nb_z = momentum_nb_z / density_nb;

                float speed_sqd_nb = velocity_nb_x*velocity_nb_x + velocity_nb_y*velocity_nb_y + velocity_nb_z*velocity_nb_z;
                float pressure_nb = (GAMMA-1.0f)*(density_energy_nb - 0.5f*density_nb*speed_sqd_nb);
                float speed_of_sound_nb = sqrtf(GAMMA*pressure_nb/density_nb);

                float fc_momentum_nb_x_x = velocity_nb_x*momentum_nb_x + pressure_nb;
                float fc_momentum_nb_x_y = velocity_nb_x*momentum_nb_y;
                float fc_momentum_nb_x_z = velocity_nb_x*momentum_nb_z;

                float fc_momentum_nb_y_x = fc_momentum_nb_x_y;
                float fc_momentum_nb_y_y = velocity_nb_y*momentum_nb_y + pressure_nb;
                float fc_momentum_nb_y_z = velocity_nb_y*momentum_nb_z;

                float fc_momentum_nb_z_x = fc_momentum_nb_x_z;
                float fc_momentum_nb_z_y = fc_momentum_nb_y_z;
                float fc_momentum_nb_z_z = velocity_nb_z*momentum_nb_z + pressure_nb;

                float de_p_nb = density_energy_nb + pressure_nb;
                float fc_density_energy_nb_x = velocity_nb_x*de_p_nb;
                float fc_density_energy_nb_y = velocity_nb_y*de_p_nb;
                float fc_density_energy_nb_z = velocity_nb_z*de_p_nb;

                float factor = -normal_len*smoothing_coefficient*0.5f*(speed_i + sqrtf(speed_sqd_nb) + speed_of_sound_i + speed_of_sound_nb);
                flux_i_density += factor*(density_i-density_nb);
                flux_i_density_energy += factor*(density_energy_i-density_energy_nb);
                flux_i_momentum_x += factor*(momentum_i_x-momentum_nb_x);
                flux_i_momentum_y += factor*(momentum_i_y-momentum_nb_y);
                flux_i_momentum_z += factor*(momentum_i_z-momentum_nb_z);

                factor = 0.5f*normal_x;
                flux_i_density += factor*(momentum_nb_x+momentum_i_x);
                flux_i_density_energy += factor*(fc_density_energy_nb_x+fc_density_energy_i_x);
                flux_i_momentum_x += factor*(fc_momentum_nb_x_x+fc_momentum_i_x_x);
                flux_i_momentum_y += factor*(fc_momentum_nb_y_x+fc_momentum_i_y_x);
                flux_i_momentum_z += factor*(fc_momentum_nb_z_x+fc_momentum_i_z_x);

                factor = 0.5f*normal_y;
                flux_i_density += factor*(momentum_nb_y+momentum_i_y);
                flux_i_density_energy += factor*(fc_density_energy_nb_y+fc_density_energy_i_y);
                flux_i_momentum_x += factor*(fc_momentum_nb_x_y+fc_momentum_i_x_y);
                flux_i_momentum_y += factor*(fc_momentum_nb_y_y+fc_momentum_i_y_y);
                flux_i_momentum_z += factor*(fc_momentum_nb_z_y+fc_momentum_i_z_y);

                factor = 0.5f*normal_z;
                flux_i_density += factor*(momentum_nb_z+momentum_i_z);
                flux_i_density_energy += factor*(fc_density_energy_nb_z+fc_density_energy_i_z);
                flux_i_momentum_x += factor*(fc_momentum_nb_x_z+fc_momentum_i_x_z);
                flux_i_momentum_y += factor*(fc_momentum_nb_y_z+fc_momentum_i_y_z);
                flux_i_momentum_z += factor*(fc_momentum_nb_z_z+fc_momentum_i_z_z);
            }
            else if(nb == -1) {
                flux_i_momentum_x += normal_x*pressure_i;
                flux_i_momentum_y += normal_y*pressure_i;
                flux_i_momentum_z += normal_z*pressure_i;
            }
            else if(nb == -2) {
                factor = 0.5f*normal_x;
                flux_i_density += factor*(ff_variable[VAR_MOMENTUM+0]+momentum_i_x);
                flux_i_density_energy += factor*(ff_flux_contribution_density_energy[0].x+fc_density_energy_i_x);
                flux_i_momentum_x += factor*(ff_flux_contribution_momentum_x[0].x + fc_momentum_i_x_x);
                flux_i_momentum_y += factor*(ff_flux_contribution_momentum_y[0].x + fc_momentum_i_y_x);
                flux_i_momentum_z += factor*(ff_flux_contribution_momentum_z[0].x + fc_momentum_i_z_x);

                factor = 0.5f*normal_y;
                flux_i_density += factor*(ff_variable[VAR_MOMENTUM+1]+momentum_i_y);
                flux_i_density_energy += factor*(ff_flux_contribution_density_energy[0].y+fc_density_energy_i_y);
                flux_i_momentum_x += factor*(ff_flux_contribution_momentum_x[0].y + fc_momentum_i_x_y);
                flux_i_momentum_y += factor*(ff_flux_contribution_momentum_y[0].y + fc_momentum_i_y_y);
                flux_i_momentum_z += factor*(ff_flux_contribution_momentum_z[0].y + fc_momentum_i_z_y);

                factor = 0.5f*normal_z;
                flux_i_density += factor*(ff_variable[VAR_MOMENTUM+2]+momentum_i_z);
                flux_i_density_energy += factor*(ff_flux_contribution_density_energy[0].z+fc_density_energy_i_z);
                flux_i_momentum_x += factor*(ff_flux_contribution_momentum_x[0].z + fc_momentum_i_x_z);
                flux_i_momentum_y += factor*(ff_flux_contribution_momentum_y[0].z + fc_momentum_i_y_z);
                flux_i_momentum_z += factor*(ff_flux_contribution_momentum_z[0].z + fc_momentum_i_z_z);
            }
        }

        fluxes[i + VAR_DENSITY*nelr] = flux_i_density;
        fluxes[i + (VAR_MOMENTUM+0)*nelr] = flux_i_momentum_x;
        fluxes[i + (VAR_MOMENTUM+1)*nelr] = flux_i_momentum_y;
        fluxes[i + (VAR_MOMENTUM+2)*nelr] = flux_i_momentum_z;
        fluxes[i + VAR_DENSITY_ENERGY*nelr] = flux_i_density_energy;
    }
}

kernel void time_step(int j, int nelr, float* old_variables, float* variables, float* step_factors, float* fluxes) {
    int i = get_global_id(0);

    if (i < nelr) {
        float factor = step_factors[i]/(RK+1-j);

        variables[i + VAR_DENSITY*nelr] = old_variables[i + VAR_DENSITY*nelr] + factor*fluxes[i + VAR_DENSITY*nelr];
        variables[i + VAR_DENSITY_ENERGY*nelr] = old_variables[i + VAR_DENSITY_ENERGY*nelr] + factor*fluxes[i + VAR_DENSITY_ENERGY*nelr];
        variables[i + (VAR_MOMENTUM+0)*nelr] = old_variables[i + (VAR_MOMENTUM+0)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+0)*nelr];
        variables[i + (VAR_MOMENTUM+1)*nelr] = old_variables[i + (VAR_MOMENTUM+1)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+1)*nelr];
        variables[i + (VAR_MOMENTUM+2)*nelr] = old_variables[i + (VAR_MOMENTUM+2)*nelr] + factor*fluxes[i + (VAR_MOMENTUM+2)*nelr];
    }
}
